member.example:
Bind a relay command to a Button's click using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ButtonCommandBinder _onConfirm;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnConfirm() { }
    }


Bind a relay command to a Button's click by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Button _target;
        
        private ButtonCommandBinder ConfirmCommand => new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnConfirm() { }
    }

Bind a relay command to a Button's click using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ButtonCommandMonoBinder _onConfirm;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnConfirm() { }
        
        [RelayCommand]
        private void OnConfirm(bool isClicked) { }
    }

Bind a relay command with one additional parameter to a Button's click.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ButtonCommandBinder<string> _onItemSelected;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnItemSelected(string itemId) { }
    }

Bind a relay command with one additional parameter using a MonoBinder component.
Because ButtonCommandMonoBinder<T> is abstract, a concrete derived class is required.

    [AddComponentMenu("MyGame/Binders/ItemSelectedCommandBinder")]
    public sealed class ItemSelectedCommandMonoBinder : ButtonCommandMonoBinder<string> { }
    
    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ItemSelectedCommandMonoBinder _onItemSelected;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void OnItemSelected(string itemId) { }
    }

